<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Desktop Environment</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Ubuntu, sans-serif;
            overflow: hidden;
        }

        #desktop {
            width: 100vw;
            height: 100vh;
            background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
            display: flex;
            flex-direction: column;
        }

        #content {
            flex: 1;
            position: relative;
            overflow: hidden;
        }

        #taskbar {
            background: rgba(20, 20, 30, 0.95);
            border-top: 1px solid rgba(255, 255, 255, 0.1);
            display: flex;
            gap: 10px;
            padding: 8px 16px;
            align-items: center;
            height: 50px;
        }

        .launcher-btn {
            padding: 6px 14px;
            background: rgba(70, 130, 180, 0.7);
            border: 1px solid rgba(100, 150, 200, 0.5);
            color: white;
            cursor: pointer;
            border-radius: 4px;
            font-size: 14px;
            transition: background 0.2s;
        }

        .launcher-btn:hover {
            background: rgba(100, 160, 200, 0.8);
        }

        .window {
            position: absolute;
            background: #2a2a3e;
            border: 1px solid rgba(100, 150, 200, 0.3);
            border-radius: 6px;
            box-shadow: 0 8px 32px rgba(0, 0, 0, 0.5);
            display: flex;
            flex-direction: column;
            min-width: 360px;
            min-height: 240px;
            z-index: 100;
        }

        .window.hidden {
            display: none;
        }

        .window-header {
            background: linear-gradient(90deg, rgba(70, 130, 180, 0.5), rgba(50, 100, 150, 0.5));
            border-bottom: 1px solid rgba(100, 150, 200, 0.2);
            padding: 8px 12px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            cursor: move;
            user-select: none;
            flex-shrink: 0;
        }

        .window-title {
            color: #e0e0e0;
            font-weight: 500;
            font-size: 14px;
        }

        .win-close {
            background: rgba(255, 100, 100, 0.7);
            border: 1px solid rgba(255, 150, 150, 0.5);
            color: white;
            cursor: pointer;
            width: 24px;
            height: 24px;
            border-radius: 3px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 14px;
            transition: background 0.2s;
        }

        .win-close:hover {
            background: rgba(255, 80, 80, 0.9);
        }

        .window-content {
            flex: 1;
            overflow: auto;
            padding: 12px;
            color: #e0e0e0;
        }

        #files-window {
            width: 500px;
            height: 400px;
            top: 100px;
            left: 100px;
        }

        .files-nav {
            display: flex;
            gap: 8px;
            margin-bottom: 10px;
            align-items: center;
        }

        #files-up {
            padding: 4px 10px;
            background: rgba(70, 130, 180, 0.6);
            border: 1px solid rgba(100, 150, 200, 0.4);
            color: white;
            cursor: pointer;
            border-radius: 3px;
            font-size: 12px;
            transition: background 0.2s;
            white-space: nowrap;
        }

        #files-up:hover {
            background: rgba(100, 160, 200, 0.7);
        }

        #files-path {
            flex: 1;
            font-family: 'Courier New', monospace;
            font-size: 13px;
            padding: 4px 8px;
            background: rgba(0, 0, 0, 0.3);
            border-radius: 3px;
            color: #64d5ff;
        }

        #files-list {
            display: flex;
            flex-direction: column;
            gap: 4px;
        }

        .fs-item {
            padding: 6px 8px;
            background: rgba(100, 100, 120, 0.3);
            border-radius: 3px;
            cursor: pointer;
            user-select: none;
            font-size: 13px;
            transition: background 0.2s;
        }

        .fs-item:hover {
            background: rgba(100, 150, 200, 0.4);
        }

        .fs-item.folder::before {
            content: '📁 ';
        }

        .fs-item.file::before {
            content: '📄 ';
        }

        #notepad-window {
            width: 450px;
            height: 350px;
            top: 150px;
            left: 650px;
        }

        #notepad-window .window-content {
            padding: 0;
            display: flex;
            flex-direction: column;
        }

        #tabs {
            display: flex;
            gap: 2px;
            background: rgba(40, 40, 60, 0.8);
            padding: 4px;
            border-bottom: 1px solid rgba(100, 150, 200, 0.2);
            overflow-x: auto;
            flex-wrap: wrap;
            flex-shrink: 0;
        }

        .tab {
            padding: 6px 12px;
            background: rgba(70, 100, 140, 0.5);
            border: 1px solid rgba(100, 150, 200, 0.3);
            color: #c0c0c0;
            cursor: pointer;
            border-radius: 3px 3px 0 0;
            font-size: 12px;
            white-space: nowrap;
            transition: background 0.2s;
        }

        .tab:hover {
            background: rgba(100, 130, 170, 0.6);
        }

        .tab.active {
            background: rgba(120, 160, 200, 0.7);
            color: #ffffff;
        }

        #new-tab {
            padding: 6px 10px;
            background: rgba(100, 150, 180, 0.6);
            border: 1px solid rgba(120, 170, 210, 0.4);
            color: white;
            cursor: pointer;
            border-radius: 3px;
            font-size: 12px;
            transition: background 0.2s;
            margin: 4px;
            flex-shrink: 0;
            width: auto;
            align-self: flex-start;
        }

        #new-tab:hover {
            background: rgba(130, 180, 210, 0.7);
        }

        #editor {
            flex: 1;
            background: rgba(30, 30, 45, 0.8);
            border: none;
            color: #e0e0e0;
            font-family: 'Courier New', monospace;
            font-size: 13px;
            padding: 8px;
            resize: none;
            margin: 0 4px 4px 4px;
        }

        #editor:focus {
            outline: none;
            box-shadow: inset 0 0 8px rgba(100, 150, 200, 0.2);
        }
    </style>
</head>
<body>
    <div id="desktop">
        <div id="content">
            <div id="files-window" class="window hidden">
                <div class="window-header">
                    <span class="window-title">File Manager</span>
                    <button class="win-close">✕</button>
                </div>
                <div class="window-content">
                    <div class="files-nav">
                        <button id="files-up">↑ Up</button>
                        <div id="files-path">/</div>
                    </div>
                    <div id="files-list"></div>
                </div>
            </div>

            <div id="notepad-window" class="window hidden">
                <div class="window-header">
                    <span class="window-title">Notepad</span>
                    <button class="win-close">✕</button>
                </div>
                <div class="window-content">
                    <div id="tabs"></div>
                    <button id="new-tab">+ New Tab</button>
                    <textarea id="editor"></textarea>
                </div>
            </div>
        </div>

        <div id="taskbar">
            <button id="open-files" class="launcher-btn">📁 Files</button>
            <button id="open-notepad" class="launcher-btn">📝 Notepad</button>
        </div>
    </div>

    <script>
        const filesystem = {
            '/': {
                bin: { type: 'folder' },
                etc: { type: 'folder' },
                home: { type: 'folder' },
                usr: { type: 'folder' },
                var: { type: 'folder' }
            },
            '/home': {
                user: { type: 'folder' }
            },
            '/home/user': {
                Documents: { type: 'folder' },
                Downloads: { type: 'folder' },
                Pictures: { type: 'folder' },
                'readme.txt': { type: 'file' }
            },
            '/home/user/Documents': {
                'notes.txt': { type: 'file' },
                'todo.txt': { type: 'file' }
            },
            '/home/user/Downloads': {
                'file1.zip': { type: 'file' }
            },
            '/home/user/Pictures': {
                'image1.jpg': { type: 'file' },
                'image2.png': { type: 'file' }
            },
            '/bin': {
                'bash': { type: 'file' },
                'ls': { type: 'file' }
            },
            '/etc': {
                'config': { type: 'folder' }
            },
            '/etc/config': {
                'system.conf': { type: 'file' }
            },
            '/usr': {
                'bin': { type: 'folder' },
                'lib': { type: 'folder' }
            },
            '/var': {}
        };

        let currentPath = '/';
        let tabs = [];
        let activeTabId = null;

        function enableDragging(windowEl) {
            const header = windowEl.querySelector('.window-header');
            let offsetX = 0, offsetY = 0;

            header.addEventListener('mousedown', (e) => {
                if (e.target.classList.contains('win-close')) return;

                offsetX = e.clientX - windowEl.offsetLeft;
                offsetY = e.clientY - windowEl.offsetTop;

                const onMouseMove = (moveEvent) => {
                    windowEl.style.left = (moveEvent.clientX - offsetX) + 'px';
                    windowEl.style.top = (moveEvent.clientY - offsetY) + 'px';
                    windowEl.style.right = 'auto';
                };

                const onMouseUp = () => {
                    document.removeEventListener('mousemove', onMouseMove);
                    document.removeEventListener('mouseup', onMouseUp);
                };

                document.addEventListener('mousemove', onMouseMove);
                document.addEventListener('mouseup', onMouseUp);
            });
        }

        function renderFilesList() {
            const list = document.getElementById('files-list');
            const pathEl = document.getElementById('files-path');
            pathEl.textContent = currentPath;

            const contents = filesystem[currentPath] || {};
            list.innerHTML = '';

            Object.entries(contents).forEach(([name, item]) => {
                const div = document.createElement('div');
                div.className = `fs-item ${item.type}`;
                div.textContent = name;

                if (item.type === 'folder') {
                    div.addEventListener('dblclick', () => {
                        let newPath = currentPath === '/' ? currentPath + name : currentPath + '/' + name;
                        if (filesystem[newPath]) {
                            currentPath = newPath;
                            renderFilesList();
                        }
                    });
                }

                list.appendChild(div);
            });
        }

        document.getElementById('files-up').addEventListener('click', () => {
            if (currentPath !== '/') {
                currentPath = currentPath.split('/').slice(0, -1).join('/') || '/';
                renderFilesList();
            }
        });

        function createNewTab() {
            const tabId = Date.now();
            const tab = { id: tabId, title: `Tab ${tabs.length + 1}`, content: '' };
            tabs.push(tab);
            activeTabId = tabId;
            saveTabs();
            renderTabs();
            renderEditor();
        }

        function switchTab(tabId) {
            const activeTab = tabs.find(t => t.id === activeTabId);
            if (activeTab) {
                activeTab.content = document.getElementById('editor').value;
            }
            activeTabId = tabId;
            saveTabs();
            renderTabs();
            renderEditor();
        }

        function renderTabs() {
            const tabsContainer = document.getElementById('tabs');
            tabsContainer.innerHTML = '';

            tabs.forEach(tab => {
                const tabEl = document.createElement('div');
                tabEl.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
                tabEl.textContent = tab.title;
                tabEl.addEventListener('click', () => switchTab(tab.id));
                tabsContainer.appendChild(tabEl);
            });
        }

        function renderEditor() {
            const editor = document.getElementById('editor');
            const activeTab = tabs.find(t => t.id === activeTabId);
            editor.value = activeTab ? activeTab.content : '';
        }

        function saveTabs() {
            localStorage.setItem('notepad_tabs', JSON.stringify(tabs));
            localStorage.setItem('notepad_activeTab', activeTabId);
        }

        function loadTabs() {
            const saved = localStorage.getItem('notepad_tabs');
            const savedActive = localStorage.getItem('notepad_activeTab');

            if (saved) {
                tabs = JSON.parse(saved);
                activeTabId = savedActive ? parseInt(savedActive) : (tabs.length > 0 ? tabs[0].id : null);
            } else {
                createNewTab();
            }
        }

        document.getElementById('new-tab').addEventListener('click', createNewTab);

        document.getElementById('editor').addEventListener('input', (e) => {
            const activeTab = tabs.find(t => t.id === activeTabId);
            if (activeTab) {
                activeTab.content = e.target.value;
                saveTabs();
            }
        });

        document.getElementById('open-files').addEventListener('click', () => {
            const filesWindow = document.getElementById('files-window');
            if (filesWindow.classList.contains('hidden')) {
                filesWindow.classList.remove('hidden');
                renderFilesList();
            }
        });

        document.getElementById('open-notepad').addEventListener('click', () => {
            const notepadWindow = document.getElementById('notepad-window');
            if (notepadWindow.classList.contains('hidden')) {
                notepadWindow.classList.remove('hidden');
                if (tabs.length === 0) {
                    loadTabs();
                }
                renderTabs();
                renderEditor();
            }
        });

        document.querySelectorAll('.win-close').forEach(btn => {
            btn.addEventListener('click', (e) => {
                const window = e.target.closest('.window');
                window.classList.add('hidden');
            });
        });

        document.querySelectorAll('.window').forEach(enableDragging);

        loadTabs();
    </script>
</body>
</html>
